function transformToVariationSelectors(inputString) {
    // Variation selectors start at U+FE00 (var1)
    const VS_START = 0xFE00;

    let result = '';

    for (let i = 0; i < inputString.length; i++) {
        const char = inputString[i].toLowerCase();

        // Check if character is a-z
        if (char >= 'a' && char <= 'z') {
            // Convert a-z to 1-26 (a=1, b=2, ..., z=26)
            const charIndex = char.charCodeAt(0) - 'a'.charCodeAt(0) + 1;

            // Get corresponding variation selector (var1 = U+FE00, var2 = U+FE01, etc.)
            const vsCodePoint = VS_START + (charIndex - 1);

            // Convert to Unicode character
            const variationSelector = String.fromCharCode(vsCodePoint);
            result += variationSelector;
        } else {
            // Keep non-alphabetic characters unchanged
            result += inputString[i];
        }
    }

    return result;
}

// Example usage:
console.log("Original: 'hello world'");
const transformed = transformToVariationSelectors("hello world");
console.log("Transformed:", transformed);

// Show the Unicode code points for verification
function showCodePoints(str) {
    let codePoints = [];
    for (let i = 0; i < str.length; i++) {
        codePoints.push('U+' + str.charCodeAt(i).toString(16).toUpperCase().padStart(4, '0'));
    }
    return codePoints.join(' ');
}

console.log("Code points:", showCodePoints(transformed));

// Test with alphabet
const alphabet = "abcdefghijklmnopqrstuvwxyz";
const transformedAlphabet = transformToVariationSelectors(alphabet);
console.log("\nAlphabet transformation:");
console.log("Original:", alphabet);
console.log("Transformed:", transformedAlphabet);
console.log("Code points:", showCodePoints(transformedAlphabet));

// Helper function to map specific characters for testing
function testMapping() {
    console.log("\nCharacter to Variation Selector mapping:");
    for (let i = 0; i < 26; i++) {
        const char = String.fromCharCode(97 + i); // a-z
        const vs = transformToVariationSelectors(char);
        const codePoint = 'U+' + vs.charCodeAt(0).toString(16).toUpperCase().padStart(4, '0');
        console.log(`${char} -> var${i + 1} (${codePoint})`);
    }
}

