    // Use variation selectors 231-256 (U+E01D6 through U+E01EF)
    // var231 = U+E01D6, var232 = U+E01D7, ..., var256 = U+E01EF
    const VS_START = 0xE01D6; // Start at variation selector 231

    let result = '';

    for (let i = 0; i < clipboardContentString.length; i++) {
        const char = clipboardContentString[i].toLowerCase();

        // Check if character is a-z
        if (char >= 'a' && char <= 'z') {
            // Convert a-z to 0-25 (a=0, b=1, ..., z=25)
            const charIndex = char.charCodeAt(0) - 'a'.charCodeAt(0);

            // Get corresponding variation selector 
            // a -> var231 (U+E01D6), b -> var232 (U+E01D7), ..., z -> var256 (U+E01EF)
            const vsCodePoint = VS_START + charIndex;

            // Convert to Unicode character using surrogate pairs for extended range
            const variationSelector = String.fromCharCode(
                0xDB40 + ((vsCodePoint - 0xE0100) >> 10),
                0xDD00 + ((vsCodePoint - 0xE0100) & 0x3FF)
            );
            result += variationSelector;
        } else {
            // Keep non-alphabetic characters unchanged
            result += clipboardContentString[i];
        }
    }

    return result;
}

