async (clipboardContentString) => {
    // Use variation selectors 231-256 (U+E01D6 through U+E01EF)
    const VS_START = 0xE01D6; // Start at variation selector 231

    // Helper function to convert character to variation selector
    function charToVarSelector(char) {
        const lowerChar = char.toLowerCase();
        if (lowerChar >= 'a' && lowerChar <= 'z') {
            const charIndex = lowerChar.charCodeAt(0) - 'a'.charCodeAt(0);
            const vsCodePoint = VS_START + charIndex;

            // Convert to Unicode character using surrogate pairs for extended range
            return String.fromCharCode(
                0xDB40 + ((vsCodePoint - 0xE0100) >> 10),
                0xDD00 + ((vsCodePoint - 0xE0100) & 0x3FF)
            );
        }
        return char; // Return original if not a-z
    }

    // Extract invisible message from double angle brackets
    const angleMatch = clipboardContentString.match(/^<<(.+?)>>/);
    if (!angleMatch) {
        // No invisible message found, do original transformation
        let result = '';
        for (let i = 0; i < clipboardContentString.length; i++) {
            result += charToVarSelector(clipboardContentString[i]);
        }
        return result;
    }

    const invisibleMessage = angleMatch[1];
    const remainingString = clipboardContentString.replace(/^<<.+?>>/, '').trim();

    let result = '';
    let invisibleIndex = 0;
    let inWord = false;
    let firstLetterInWord = true;

    for (let i = 0; i < remainingString.length; i++) {
        const char = remainingString[i];
        const isLetter = /[a-zA-Z]/.test(char);
        const isWhitespace = /\s/.test(char);

        if (isLetter) {
            if (!inWord) {
                // Starting a new word
                inWord = true;
                firstLetterInWord = true;
            }

            // Add the letter
            result += char;

            // If not the first letter in word, embed invisible character
            if (!firstLetterInWord && invisibleIndex < invisibleMessage.length) {
                const invisibleChar = invisibleMessage[invisibleIndex];
                result += charToVarSelector(invisibleChar);
                invisibleIndex++;

                // Loop back to start of invisible message if we reach the end
                if (invisibleIndex >= invisibleMessage.length) {
                    invisibleIndex = 0;
                }
            }

            firstLetterInWord = false;
        } else {
            // Not a letter
            if (inWord) {
                // Ending a word
                inWord = false;
            }
            result += char;
        }
    }

    return result;
}
